{
  "name": "Fruitas V9.0 - Excel Replicator",
  "description": "A high-performance React application for managing fruit orders across multiple locations with Excel synchronization and advanced calculation features."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface LocationData {
  [key: string]: string;
}

export interface Product {
  code: string;
  name: string;
  unit: string;
  multiplier?: number;
  locations: LocationData;
}

export interface ColumnDefinition {
  key: string;
  label: string;
  width: string;
  color?: string;
  isAction?: boolean;
}

export interface Feedback {
  message: string;
  isError: boolean;
}

import React, { useState, useRef, useCallback } from 'react';
import { Product, Feedback, ColumnDefinition } from './types';
import { INITIAL_DATA, COLUMNS } from './constants';
import Header from './components/Header';
import DataTable from './components/DataTable';
import Toast from './components/Toast';

const App: React.FC = () => {
  const [data, setData] = useState<Product[]>(INITIAL_DATA);
  const [feedback, setFeedback] = useState<Feedback | null>(null);
  const [showImport, setShowImport] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const notify = useCallback((message: string, isError = false) => {
    setFeedback({ message, isError });
    if (!isError) {
      setTimeout(() => setFeedback(null), 3000);
    }
  }, []);

  const handleCellChange = useCallback((rowIndex: number, colKey: string, value: string) => {
    setData(prev => {
      const newData = [...prev];
      if (['code', 'name', 'unit'].includes(colKey)) {
        // @ts-ignore
        newData[rowIndex][colKey] = value;
      } else {
        newData[rowIndex].locations = {
          ...newData[rowIndex].locations,
          [colKey]: value
        };
      }
      return newData;
    });
  }, []);

  const cleanString = (val: any): string => {
    if (val === null || val === undefined) return "";
    return String(val).trim().toUpperCase();
  };

  const clearAllLocations = useCallback(() => {
    setData(prev => prev.map(row => ({
      ...row,
      locations: {}
    })));
    if (fileInputRef.current) fileInputRef.current.value = "";
    notify("Datos de cantidades eliminados.");
  }, [notify]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        // @ts-ignore
        const bstr = evt.target.result;
        // @ts-ignore
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        // @ts-ignore
        const jsonData: any[][] = XLSX.utils.sheet_to_json(ws, { header: 1 });

        setData(prev => {
          const newData = [...prev];
          let matchCount = 0;

          jsonData.forEach((row) => {
            if (!row || row.length < 2) return;
            const excelCode = cleanString(row[0]);
            const excelName = cleanString(row[1]);

            const idx = newData.findIndex(d => 
              cleanString(d.code) === excelCode || 
              cleanString(d.name) === excelName ||
              (excelName.length > 5 && cleanString(d.name).includes(excelName))
            );

            if (idx !== -1) {
              matchCount++;
              COLUMNS.slice(3).forEach((col, colIdx) => {
                const excelColIdx = colIdx + 3;
                if (row[excelColIdx] !== undefined) {
                  const val = String(row[excelColIdx]).trim();
                  if (val !== "" && val !== "undefined" && val !== "null") {
                    newData[idx].locations[col.key] = val;
                  }
                }
              });
            }
          });

          notify(`¡Procesado! ${matchCount} productos actualizados.`);
          return newData;
        });
        setShowImport(false);
      } catch (err) {
        notify("Error al leer el archivo Excel.", true);
      }
    };
    reader.readAsBinaryString(file);
  };

  const calculateTotalValue = (val: string, multiplier?: number) => {
    if (!multiplier || !val || val.trim() === '' || val.trim() === '0') return val;
    const num = parseFloat(val.replace(',', '.'));
    if (isNaN(num)) return val;
    return (num * multiplier).toFixed(2).replace('.', ',');
  };

  const copyFullTable = useCallback(() => {
    let tsv = COLUMNS.map(col => col.label).join('\t') + '\n';
    let count = 0;
    data.forEach(row => {
      const hasValue = Object.values(row.locations).some(v => v && v.trim() !== "" && v.trim() !== "0");
      if (hasValue) {
        count++;
        const line = [
          row.code, row.name, row.unit,
          ...COLUMNS.slice(3).map(col => calculateTotalValue(row.locations[col.key] || "", row.multiplier))
        ].join('\t');
        tsv += line + '\n';
      }
    });

    if (count === 0) {
      notify("No hay datos para copiar.", true);
      return;
    }

    navigator.clipboard.writeText(tsv).then(() => {
      notify(`Copiadas ${count} filas a portapapeles.`);
    });
  }, [data, notify]);

  const copyColumnWithCode = useCallback((colKey: string) => {
    const colConfig = COLUMNS.find(c => c.key === colKey);
    let tsv = "";
    let count = 0;
    data.forEach(row => {
      const val = row.locations[colKey];
      if (val && val.trim() !== "" && val.trim() !== "0") {
        count++;
        const finalVal = calculateTotalValue(val, row.multiplier);
        tsv += `${row.code}\t${finalVal}\n`;
      }
    });

    if (count === 0) {
      notify(`La columna ${colConfig?.label} está vacía.`, true);
      return;
    }

    navigator.clipboard.writeText(tsv).then(() => {
      notify(`Copiado: ${count} filas (${colConfig?.label})`);
    });
  }, [data, notify]);

  return (
    <div className="flex flex-col h-screen bg-slate-50">
      <Header 
        onImportToggle={() => setShowImport(!showImport)}
        onClear={clearAllLocations}
        onCopyAll={copyFullTable}
      />

      {feedback && (
        <Toast 
          message={feedback.message} 
          isError={feedback.isError} 
          onClose={() => setFeedback(null)} 
        />
      )}

      {showImport && (
        <div className="bg-slate-100 p-6 border-b border-slate-200 animate-slideIn text-center">
          <input 
            ref={fileInputRef} 
            type="file" 
            accept=".xlsx, .xls" 
            onChange={handleFileUpload} 
            className="hidden" 
          />
          <div 
            onClick={() => fileInputRef.current?.click()} 
            className="max-w-xl mx-auto border-2 border-dashed border-slate-300 rounded-2xl p-10 hover:border-blue-500 hover:bg-white transition-all cursor-pointer group"
          >
            <div className="flex flex-col items-center gap-2">
              <svg className="w-10 h-10 text-slate-400 group-hover:text-blue-500 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
              </svg>
              <p className="font-bold text-slate-700 uppercase tracking-tight">Seleccionar archivo Excel de pedido</p>
              <p className="text-xs text-slate-400">Formatos soportados: .xlsx, .xls</p>
            </div>
          </div>
        </div>
      )}

      <main className="flex-1 overflow-auto bg-slate-200/50 p-4">
        <DataTable 
          data={data}
          columns={COLUMNS}
          onCellChange={handleCellChange}
          onCopyColumn={copyColumnWithCode}
          calculateValue={calculateTotalValue}
        />
      </main>

      <footer className="bg-white border-t border-slate-200 px-6 py-2 text-[10px] text-slate-400 font-medium flex justify-between items-center">
        <span>FRUITAS V9.0 SYSTEM</span>
        <div className="flex gap-4">
          <span>{data.length} Productos</span>
          <span>Sincronización Activa</span>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React from 'react';

interface HeaderProps {
  onImportToggle: () => void;
  onClear: () => void;
  onCopyAll: () => void;
}

const Header: React.FC<HeaderProps> = ({ onImportToggle, onClear, onCopyAll }) => {
  return (
    <header className="bg-slate-900 text-white px-6 py-4 flex flex-col md:flex-row justify-between items-center gap-4 shadow-2xl z-30 shrink-0">
      <div className="flex items-center gap-4">
        <div className="bg-blue-600 p-2.5 rounded-xl shadow-lg shadow-blue-900/20 ring-1 ring-blue-400/50">
          <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
            <path d="M11 20H4a2 2 0 0 1-2-2V5c0-1.1.9-2 2-2h5l2 3h9a2 2 0 0 1 2 2v10" />
            <path d="M11 20l4-4" />
            <path d="M11 20l4 4" />
            <path d="M11 20h11" />
          </svg>
        </div>
        <div>
          <h1 className="text-xl font-black tracking-tighter uppercase leading-none italic">FRUITAS V9.0</h1>
          <p className="text-[10px] text-blue-400 font-bold tracking-[0.15em] uppercase mt-1">Sincronización Nativa Excel</p>
        </div>
      </div>

      <div className="flex items-center gap-2">
        <button
          onClick={onImportToggle}
          className="bg-slate-800 hover:bg-slate-700 text-white px-5 py-2.5 rounded-xl font-bold text-xs transition-all border border-slate-700 active:scale-95 flex items-center gap-2"
        >
          SUBIR EXCEL
        </button>
        <button
          onClick={onClear}
          className="bg-rose-600 hover:bg-rose-500 text-white px-5 py-2.5 rounded-xl font-bold text-xs shadow-[0_4px_0_rgb(159,18,57)] active:translate-y-1 active:shadow-none transition-all flex items-center gap-2"
        >
          LIMPIAR
        </button>
        <button
          onClick={onCopyAll}
          className="bg-emerald-500 hover:bg-emerald-400 text-emerald-950 px-6 py-2.5 rounded-xl font-black text-xs shadow-[0_4px_0_rgb(5,150,105)] active:translate-y-1 active:shadow-none transition-all flex items-center gap-2"
        >
          COPIAR TODO
        </button>
      </div>
    </header>
  );
};

export default Header;

import React from 'react';
import { Product, ColumnDefinition } from '../types';

interface DataTableProps {
  data: Product[];
  columns: ColumnDefinition[];
  onCellChange: (rowIndex: number, colKey: string, value: string) => void;
  onCopyColumn: (colKey: string) => void;
  calculateValue: (val: string, multiplier?: number) => string;
}

const DataTable: React.FC<DataTableProps> = ({ 
  data, 
  columns, 
  onCellChange, 
  onCopyColumn, 
  calculateValue 
}) => {
  return (
    <div className="bg-white rounded-2xl shadow-xl border border-slate-200 overflow-hidden">
      <div className="overflow-x-auto">
        <table className="w-full text-left border-collapse table-fixed min-w-[1400px]">
          <thead className="bg-slate-900 sticky top-0 z-20 text-white shadow-md">
            <tr>
              {columns.map((col, idx) => (
                <th key={col.key} className={`${col.width} p-0 text-center relative border-r border-slate-800 last:border-0`}>
                  <div className="py-4 px-2 flex flex-col items-center justify-between min-h-[100px]">
                    <span className={`text-[11px] font-black uppercase flex items-center text-center px-1 mb-3 h-10 ${idx < 3 ? 'text-slate-400' : 'text-white'}`}>
                      {col.label}
                    </span>
                    {idx >= 3 && (
                      <button 
                        onClick={() => onCopyColumn(col.key)} 
                        className="bg-blue-600 hover:bg-blue-500 text-white text-[9px] font-extrabold py-1.5 px-3 rounded-lg shadow-[0_2px_0_rgb(29,78,216)] transition-all uppercase tracking-tight"
                      >
                        COPIAR + CÓD
                      </button>
                    )}
                  </div>
                </th>
              ))}
            </tr>
          </thead>

          <tbody className="divide-y divide-slate-100">
            {data.map((row, rIndex) => (
              <tr key={rIndex} className="hover:bg-blue-50/50 group transition-colors divide-x divide-slate-100">
                <td className="px-2 py-3 text-[11px] font-bold text-slate-400 text-center bg-slate-50/50">
                  {row.code}
                </td>
                <td className="px-4 py-3 text-sm font-bold text-slate-800 uppercase truncate group-hover:text-blue-600 transition-colors">
                  {row.name}
                </td>
                <td className="px-2 py-3 text-[10px] text-slate-400 font-extrabold uppercase text-center bg-slate-50/30">
                  <div className="flex flex-col">
                    <span>{row.unit}</span>
                    {row.multiplier && (
                      <span className="text-[9px] text-emerald-600 mt-0.5">({row.multiplier} KG)</span>
                    )}
                  </div>
                </td>

                {columns.slice(3).map((col) => {
                  const val = row.locations[col.key] || "";
                  const totalVal = calculateValue(val, row.multiplier);
                  const hasOrder = val.trim() !== '' && val.trim() !== '0';

                  return (
                    <td key={col.key} className={`p-0 relative transition-all group/cell ${hasOrder ? 'bg-blue-50/80' : ''}`}>
                      <input
                        type="text"
                        value={val}
                        onChange={(e) => onCellChange(rIndex, col.key, e.target.value)}
                        className={`w-full h-full min-h-[56px] p-2 text-center text-sm font-black bg-transparent border-0 outline-none transition-all placeholder:text-slate-300 focus:bg-white focus:ring-2 focus:ring-blue-500 focus:ring-inset ${hasOrder ? 'text-blue-700' : 'text-slate-400'}`}
                        placeholder="-"
                      />
                      {row.multiplier && hasOrder && (
                        <div className="absolute top-1 right-1 px-1.5 py-0.5 text-[9px] font-black text-white bg-emerald-500 rounded-md shadow-sm pointer-events-none transform scale-90 origin-top-right">
                          {totalVal}
                        </div>
                      )}
                    </td>
                  );
                })}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default DataTable;

import React from 'react';

interface ToastProps {
  message: string;
  isError: boolean;
  onClose: () => void;
}

const Toast: React.FC<ToastProps> = ({ message, isError, onClose }) => {
  return (
    <div className={`fixed top-24 right-8 p-5 rounded-2xl shadow-2xl z-50 border-b-4 animate-slideIn flex items-center gap-4 transition-all ${
      isError 
        ? 'bg-rose-600 text-white border-rose-800' 
        : 'bg-slate-900 text-blue-400 border-blue-600'
    }`}>
      <div className="flex items-center gap-3">
        {isError ? (
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
          </svg>
        ) : (
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
          </svg>
        )}
        <span className="font-black text-xs uppercase tracking-widest">{message}</span>
      </div>
      <button 
        onClick={onClose} 
        className="text-white/50 hover:text-white transition-colors"
      >
        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" />
        </svg>
      </button>
    </div>
  );
};

export default Toast;

