    });
  }, [data, notify]);

  const copyColumnWithCode = useCallback((colKey: string) => {
    const colConfig = COLUMNS.find(c => c.key === colKey);
    let tsv = "";
    let count = 0;
    data.forEach(row => {
      const val = row.locations[colKey];
      if (val && val.trim() !== "" && val.trim() !== "0") {
        count++;
        const finalVal = calculateTotalValue(val, row.multiplier);
        tsv += `${row.code}\t${finalVal}\n`;
      }
    });

    if (count === 0) {
      notify(`La columna ${colConfig?.label} está vacía.`, true);
      return;
    }

    navigator.clipboard.writeText(tsv).then(() => {
      notify(`Copiado: ${count} filas de ${colConfig?.label}`);
    });
  }, [data, notify]);

  return (
    <div className="flex flex-col h-screen bg-slate-50">
      <Header 
        onImportToggle={() => setShowImport(!showImport)}
