      {showImport && (
        <div className="bg-slate-100 p-8 border-b-2 border-slate-200 animate-slideIn shadow-inner">
          <input 
            ref={fileInputRef} 
            type="file" 
            accept=".xlsx, .xls, .csv" 
            onChange={handleFileUpload} 
            className="hidden" 
          />
          <div 
            onClick={() => fileInputRef.current?.click()} 
            className="max-w-2xl mx-auto border-4 border-dashed border-slate-300 rounded-3xl p-12 hover:border-blue-500 hover:bg-white transition-all cursor-pointer group bg-slate-50/50 flex flex-col items-center gap-4"
