import React, { useState, useRef, useCallback } from 'react';
import { Product, Feedback, ColumnDefinition } from './types';
import { INITIAL_DATA, COLUMNS } from './constants';
import Header from './components/Header';
import DataTable from './components/DataTable';
import Toast from './components/Toast';

const App: React.FC = () => {
  const [data, setData] = useState<Product[]>(INITIAL_DATA);
  const [feedback, setFeedback] = useState<Feedback | null>(null);
  const [showImport, setShowImport] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const notify = useCallback((message: string, isError = false) => {
    setFeedback({ message, isError });
    if (!isError) {
      setTimeout(() => setFeedback(null), 5000);
    }
  }, []);

  const handleCellChange = useCallback((rowIndex: number, colKey: string, value: string) => {
    setData(prev => {
      const newData = [...prev];
      const targetRow = { ...newData[rowIndex] };

      if (['code', 'name', 'unit'].includes(colKey)) {
        // @ts-ignore
        targetRow[colKey] = value;
      } else {
        targetRow.locations = {
          ...targetRow.locations,
          [colKey]: value
        };
      }

      newData[rowIndex] = targetRow;
      return newData;
    });
  }, []);

  const normalize = (val: any): string => {
    if (val === null || val === undefined) return "";
    return String(val)
      .trim()
      .normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "") 
      .toUpperCase()
      .replace(/\s+/g, ' ');
  };

  const clearAllLocations = useCallback(() => {
    setData(prev => prev.map(row => ({
      ...row,
      locations: {}
    })));
    if (fileInputRef.current) fileInputRef.current.value = "";
    notify("Datos de cantidades eliminados.");
  }, [notify]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const dataBuffer = evt.target?.result;
        const XLSX = (window as any).XLSX;
        if (!XLSX) throw new Error("Librería Excel no cargada");

        const wb = XLSX.read(dataBuffer, { type: 'array' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const jsonData: any[][] = XLSX.utils.sheet_to_json(ws, { header: 1 });

        if (jsonData.length === 0) {
          notify("El archivo está vacío.", true);
          return;
        }

        setData(prev => {
          const newData = prev.map(item => ({
            ...item,
            locations: { ...item.locations }
          }));

          let matchCount = 0;
          let locationColMappings: { [key: string]: number } = {};

          // 1. Detectar cabeceras con protección contra undefined
          for (let i = 0; i < Math.min(jsonData.length, 25); i++) {
            const row = jsonData[i];
            if (!row) continue;
            // Array.from evita errores con arrays dispersos (holes) en Excel
            const rowNorm = Array.from(row).map(c => normalize(c));

            const fCode = rowNorm.findIndex(c => c && c.includes("COD"));
            const fName = rowNorm.findIndex(c => c && (c.includes("PROD") || c.includes("ART") || c.includes("NOM")));

            if (fCode !== -1 || fName !== -1) {
              COLUMNS.slice(3).forEach(col => {
                const keyword = normalize(col.label).split(' ')[0];
                const foundLoc = rowNorm.findIndex(c => c && c.includes(keyword));
                if (foundLoc !== -1) locationColMappings[col.key] = foundLoc;
              });
              if (Object.keys(locationColMappings).length > 0) break;
            }
          }

          // 2. Procesar Filas con escaneo ampliado
          jsonData.forEach((row) => {
            if (!row || row.length < 1) return;

            let targetIdx = -1;
            // Escaneamos hasta 15 columnas para encontrar el producto (algunos Excels tienen columnas vacías al inicio)
            const searchLimit = Math.min(row.length, 15);

            for (let c = 0; c < searchLimit; c++) {
              const cellVal = normalize(row[c]);
              if (!cellVal || cellVal.length < 1) continue;

              targetIdx = newData.findIndex(d => {
                const dCode = normalize(d.code);
                const dName = normalize(d.name);
                return dCode === cellVal || dName === cellVal || (cellVal.length > 5 && dName.includes(cellVal));
              });

              if (targetIdx !== -1) break;
            }

            if (targetIdx !== -1) {
              matchCount++;
              COLUMNS.slice(3).forEach((col, colIdx) => {
                let valToStore = "";
                if (locationColMappings[col.key] !== undefined) {
                  valToStore = String(row[locationColMappings[col.key]] || "").trim();
                } else {
                  const fallbackIdx = colIdx + 3;
                  valToStore = String(row[fallbackIdx] || "").trim();
                }

                if (valToStore !== "" && valToStore.toLowerCase() !== "undefined" && valToStore !== "0") {
                  newData[targetIdx].locations[col.key] = valToStore;
                }
              });
            }
          });

          if (matchCount > 0) {
            notify(`¡Sincronizado! ${matchCount} productos actualizados.`);
          } else {
            notify("No se encontraron productos conocidos. Revisa el formato.", true);
          }

          return newData;
        });

        setShowImport(false);
        if (fileInputRef.current) fileInputRef.current.value = "";

      } catch (err) {
        console.error(err);
        notify("Error al procesar el archivo.", true);
      }
    };
    reader.readAsArrayBuffer(file);
  };

  const calculateTotalValue = (val: string, multiplier?: number) => {
    if (!multiplier || !val || val.trim() === '' || val.trim() === '0') return val;
    const num = parseFloat(val.replace(',', '.'));
    if (isNaN(num)) return val;
    return (num * multiplier).toFixed(2).replace('.', ',');
  };

  const copyFullTable = useCallback(() => {
    let tsv = COLUMNS.map(col => col.label).join('\t') + '\n';
    let count = 0;
    data.forEach(row => {
      const hasValue = (Object.values(row.locations) as string[]).some(v => v && v.trim() !== "" && v.trim() !== "0");
      if (hasValue) {
        count++;
        const line = [
          row.code, row.name, row.unit,
          ...COLUMNS.slice(3).map(col => calculateTotalValue(row.locations[col.key] || "", row.multiplier))
        ].join('\t');
        tsv += line + '\n';
      }
    });

    if (count === 0) {
      notify("No hay datos cargados para copiar.", true);
      return;
    }

    navigator.clipboard.writeText(tsv).then(() => {
      notify(`Copiadas ${count} filas.`);
    });
  }, [data, notify]);

  const copyColumnWithCode = useCallback((colKey: string) => {
    const colConfig = COLUMNS.find(c => c.key === colKey);
    let tsv = "";
    let count = 0;
    data.forEach(row => {
      const val = row.locations[colKey];
      if (val && val.trim() !== "" && val.trim() !== "0") {
        count++;
        const finalVal = calculateTotalValue(val, row.multiplier);
        tsv += `${row.code}\t${finalVal}\n`;
      }
    });

    if (count === 0) {
      notify(`La columna ${colConfig?.label} está vacía.`, true);
      return;
    }

    navigator.clipboard.writeText(tsv).then(() => {
      notify(`Copiado: ${count} filas (${colConfig?.label})`);
    });
  }, [data, notify]);

  return (
    <div className="flex flex-col h-screen bg-slate-50">
      <Header 
        onImportToggle={() => setShowImport(!showImport)}
        onClear={clearAllLocations}
        onCopyAll={copyFullTable}
      />

      {feedback && (
        <Toast 
          message={feedback.message} 
          isError={feedback.isError} 
          onClose={() => setFeedback(null)} 
        />
      )}

      {showImport && (
        <div className="bg-slate-100 p-8 border-b-2 border-slate-200 animate-slideIn shadow-inner">
          <input 
            ref={fileInputRef} 
            type="file" 
            accept=".xlsx, .xls, .csv" 
            onChange={handleFileUpload} 
            className="hidden" 
          />
          <div 
            onClick={() => fileInputRef.current?.click()} 
            className="max-w-2xl mx-auto border-4 border-dashed border-slate-300 rounded-3xl p-12 hover:border-blue-500 hover:bg-white transition-all cursor-pointer group bg-slate-50/50 flex flex-col items-center gap-4"
          >
            <div className="bg-blue-600 p-5 rounded-2xl text-white shadow-xl shadow-blue-200 group-hover:scale-110 transition-transform">
              <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
              </svg>
            </div>
            <div className="text-center">
              <p className="font-black text-slate-800 text-xl uppercase tracking-tight">Seleccionar Excel</p>
              <p className="text-slate-500 font-medium mt-1 uppercase text-xs tracking-widest">Detección automática de filas y columnas corregida</p>
            </div>
          </div>
        </div>
      )}

      <main className="flex-1 overflow-auto bg-slate-200/50 p-4">
        <DataTable 
          data={data}
          columns={COLUMNS}
          onCellChange={handleCellChange}
          onCopyColumn={copyColumnWithCode}
          calculateValue={calculateTotalValue}
        />
      </main>

      <footer className="bg-slate-900 border-t border-slate-800 px-6 py-3 text-[10px] text-slate-400 font-bold flex justify-between items-center shrink-0">
        <div className="flex items-center gap-3">
          <span className="flex h-2 w-2 relative">
            <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-emerald-400 opacity-75"></span>
            <span className="relative inline-flex rounded-full h-2 w-2 bg-emerald-500"></span>
          </span>
          <span className="uppercase tracking-[0.2em] text-emerald-500/80">Motor de Sincronización V9.0.1</span>
        </div>
        <div className="flex gap-8 uppercase tracking-widest items-center">
          <span className="bg-slate-800 px-3 py-1 rounded text-slate-300">{data.length} Productos</span>
          <span className="text-slate-700">|</span>
          <span className="text-blue-400">Escaneo de 15 columnas activo</span>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useRef, useCallback } from 'react';
import { Product, Feedback } from './types';
import { INITIAL_DATA, COLUMNS } from './constants';
