const App: React.FC = () => {
  const [data, setData] = useState<Product[]>(INITIAL_DATA);
  const [feedback, setFeedback] = useState<Feedback | null>(null);
  const [showImport, setShowImport] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const notify = useCallback((message: string, isError = false) => {
    setFeedback({ message, isError });
    if (!isError) {
      setTimeout(() => setFeedback(null), 5000);
    }
  }, []);

  const handleCellChange = useCallback((rowIndex: number, colKey: string, value: string) => {
    setData(prev => {
      const newData = [...prev];
      const targetRow = { ...newData[rowIndex] };
      if (['code', 'name', 'unit'].includes(colKey)) {
        // @ts-ignore
        targetRow[colKey] = value;
      } else {
        targetRow.locations = { ...targetRow.locations, [colKey]: value };
      }
      newData[rowIndex] = targetRow;
      return newData;
    });
  }, []);

  const normalize = (val: any): string => {
    if (val === null || val === undefined) return "";
    return String(val)
      .trim()
      .normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "") // Quitar acentos
      .toUpperCase()
      .replace(/\s+/g, ' ');
  };

  const clearAllLocations = useCallback(() => {
    setData(prev => prev.map(row => ({ ...row, locations: {} })));
    if (fileInputRef.current) fileInputRef.current.value = "";
    notify("Cantidades limpiadas.");
  }, [notify]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const dataBuffer = evt.target?.result;
        const XLSX = (window as any).XLSX;
        if (!XLSX) throw new Error("SheetJS no disponible");

        const wb = XLSX.read(dataBuffer, { type: 'array' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const jsonData: any[][] = XLSX.utils.sheet_to_json(ws, { header: 1, defval: "" });

        if (jsonData.length === 0) {
          notify("El archivo está vacío.", true);
          return;
        }

        setData(prev => {
          const newData = prev.map(item => ({
            ...item,
            locations: { ...item.locations }
          }));

          let matchCount = 0;
          let colMapping: { [key: string]: number } = {};

          // 1. ESCANEO DE CABECERAS (Busca en las primeras 30 filas)
          for (let i = 0; i < Math.min(jsonData.length, 30); i++) {
            const row = jsonData[i] || [];
            const rowNorm = Array.from(row).map(c => normalize(c));

            // Si encontramos algo que parezca "COD" o "PRODUCTO", mapeamos tiendas
            if (rowNorm.some(c => c.includes("COD") || c.includes("ART") || c.includes("PROD"))) {
              COLUMNS.slice(3).forEach(col => {
                const keyword = normalize(col.label).split(' ')[0];
                const foundIdx = rowNorm.findIndex(c => c && c.includes(keyword));
                if (foundIdx !== -1) colMapping[col.key] = foundIdx;
              });
            }
          }

          // 2. PROCESAMIENTO DE FILAS (Escaneo profundo)
          jsonData.forEach((row) => {
            if (!row || row.length === 0) return;

            let targetIdx = -1;
            const searchRange = Math.min(row.length, 20); // Miramos hasta la columna 20

            // Buscamos si el código o nombre del producto está en CUALQUIER celda de la fila
            for (let c = 0; c < searchRange; c++) {
              const cellVal = normalize(row[c]);
              if (!cellVal) continue;

              targetIdx = newData.findIndex(p => {
                const pCode = normalize(p.code);
                const pName = normalize(p.name);
                // Coincidencia exacta de código o nombre, o nombre contenido
                return (pCode === cellVal && pCode !== "") || 
                       (pName === cellVal && pName !== "") ||
                       (cellVal.length > 6 && pName.includes(cellVal));
              });

              if (targetIdx !== -1) break;
            }

            // Si encontramos el producto, extraemos cantidades
            if (targetIdx !== -1) {
              matchCount++;
              COLUMNS.slice(3).forEach((col, colIdx) => {
                let val = "";
                // Si detectamos la columna de la tienda por nombre, la usamos
                if (colMapping[col.key] !== undefined) {
                  val = String(row[colMapping[col.key]] || "").trim();
                } else {
                  // Si no, usamos posición relativa (Cód+0, Nom+1, Unit+2, Tienda1+3...)
                  const fallbackIdx = colIdx + 3;
                  val = String(row[fallbackIdx] || "").trim();
                }

                if (val !== "" && val !== "0" && val.toLowerCase() !== "undefined") {
                  newData[targetIdx].locations[col.key] = val;
                }
              });
            }
          });

          if (matchCount > 0) {
            notify(`Sincronizados ${matchCount} productos correctamente.`);
          } else {
            notify("No se encontraron coincidencias. Revisa si los códigos coinciden.", true);
          }

          return newData;
        });

        setShowImport(false);
        if (fileInputRef.current) fileInputRef.current.value = "";

      } catch (err) {
        console.error(err);
        notify("Error al leer el archivo Excel.", true);
      }
    };
    reader.readAsArrayBuffer(file);
  };

  const calculateTotalValue = (val: string, multiplier?: number) => {
    if (!multiplier || !val || val.trim() === '' || val.trim() === '0') return val;
    const num = parseFloat(val.replace(',', '.'));
    if (isNaN(num)) return val;
    return (num * multiplier).toFixed(2).replace('.', ',');
  };

  const copyFullTable = useCallback(() => {
    let tsv = COLUMNS.map(col => col.label).join('\t') + '\n';
    let count = 0;
