        const line = [
          row.code, row.name, row.unit,
          ...COLUMNS.slice(3).map(col => calculateTotalValue(row.locations[col.key] || "", row.multiplier))
        ].join('\t');
        tsv += line + '\n';
      }
    });
    if (count === 0) return notify("No hay datos para copiar.", true);
    navigator.clipboard.writeText(tsv).then(() => notify(`Copiadas ${count} filas.`));
  }, [data, notify]);

  const copyColumnWithCode = useCallback((colKey: string) => {
    const colConfig = COLUMNS.find(c => c.key === colKey);
    let tsv = "";
    let count = 0;
    data.forEach(row => {
      const val = row.locations[colKey];
      if (val && val !== "" && val !== "0") {
        count++;
        tsv += `${row.code}\t${calculateTotalValue(val, row.multiplier)}\n`;
      }
    });
    if (count === 0) return notify("Columna vacía.", true);
    navigator.clipboard.writeText(tsv).then(() => notify(`Copiado ${colConfig?.label}`));
  }, [data, notify]);

  return (
    <div className="flex flex-col h-screen bg-slate-50">
      <Header 
        onImportToggle={() => setShowImport(!showImport)}
        onClear={clearAllLocations}
        onCopyAll={copyFullTable}
      />

      {feedback && <Toast {...feedback} onClose={() => setFeedback(null)} />}

      {showImport && (
        <div className="bg-white p-8 border-b-4 border-blue-100 animate-slideIn shadow-inner flex justify-center">
          <input ref={fileInputRef} type="file" accept=".xlsx, .xls" onChange={handleFileUpload} className="hidden" />
          <div 
            onClick={() => fileInputRef.current?.click()} 
            className="w-full max-w-2xl border-4 border-dashed border-slate-200 rounded-3xl p-12 hover:border-blue-500 hover:bg-blue-50 transition-all cursor-pointer text-center"
          >
            <div className="inline-block p-4 bg-blue-600 rounded-2xl text-white mb-4">
              <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" /></svg>
            </div>
            <h2 className="text-xl font-black text-slate-800 uppercase italic">Haz clic para cargar el pedido</h2>
            <p className="text-slate-400 text-xs font-bold mt-2 uppercase tracking-widest">Formatos soportados: Excel (.xlsx, .xls)</p>
          </div>
        </div>
      )}

      <main className="flex-1 overflow-auto p-4 bg-slate-200/40">
        <DataTable 
          data={data}
          columns={COLUMNS}
          onCellChange={handleCellChange}
          onCopyColumn={copyColumnWithCode}
          calculateValue={calculateTotalValue}
        />
